INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24001, "2030/12/17 14:59:59", 1, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 0, 0.0, 1, "あたしだって\nやるときはやるよ！");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24002, "2030/12/17 14:59:59", 1, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 1, 0.0, 1, "ふぅ…\nこれであたしの仕事は\n終わりだね");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24003, "2030/12/17 14:59:59", 1, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 2, 0.0, 1, "終わった終わった\n一人でもなんとか\nなるもんだね");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24004, "2030/12/17 14:59:59", 2, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 3, 0.0, 2, "やったね！\nこれでようやく\nサボれるよ…");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24005, "2030/12/17 14:59:59", 1, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 4, 0.0, 1, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24006, "2030/12/17 14:59:59", 2, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 5, 0.0, 2, "あたしを敵に回した\n恐ろしさ\n思い知ったか！");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24007, "2030/12/17 14:59:59", 2, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 6, 0.0, 2, "あたしも意外と\nやるもんでしょ？");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24008, "2030/12/17 14:59:59", 4, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 7, 0.0, 4, "疲れた…\nねずみの逃げ足\n速すぎるよ…");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24009, "2030/12/17 14:59:59", 4, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 8, 0.0, 4, "このままじゃ\nまっひ～に\n叱られちゃうよ");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24010, "2030/12/17 14:59:59", 4, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 9, 0.0, 4, "まじめに\nやったんだけどな…\n悔しいな～");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24011, "2030/12/17 14:59:59", 4, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 10, 0.0, 4, "やられた…\nねずみって意外と\nてごわいね");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24012, "2030/12/17 14:59:59", 4, "2020/04/30 12:00:00", 0.0, 0.0, "リン", 11, 0.0, 4, "おのれ～\nあたしのチーズを\n盗みやがって～！");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (24, 102601, 10040, 24013, "2030/12/17 14:59:59", 1, "2020/04/30 12:00:00", 1.81, 0.0, "リン", 12, 0.0, 4, "疲れた…\nけど、次こそは\n守り抜くよ…");
